import json, os

OFFLINE_KB = {'wheat': "## Wheat Farming Guide (ICAR Recommended)\n## Summary\nWheat (Triticum aestivum) is India's second most important cereal — Rabi crop sown Oct-Dec, harvested Mar-Apr.\n## Details\n- **Best varieties:** HD-3086, HD-2967, GW-322, PBW-550, DBW-187 (ICAR released)\n- **Soil:** Loamy/clay-loam, pH 6.0–7.5, well-drained\n- **Seed rate:** 100 kg/ha (timely), 125 kg/ha (late sowing)\n- **Spacing:** 20–22 cm row-to-row\n- **Yield potential:** 4–6 tonnes/ha with good management\n## Steps\n1. Deep plough 2–3 times; last plough with rotavator for fine tilth\n2. Basal dose: 60 kg N + 60 kg P + 40 kg K per hectare before sowing\n3. Sow seeds 5 cm deep with seed drill; treat seeds with Thiram 2.5 g/kg\n4. First irrigation (Crown Root Initiation) at 20–25 days after sowing\n5. Top dress 60 kg N/ha at first irrigation\n6. Total 5–6 irrigations; last at dough stage\n7. Harvest at 14% grain moisture; thresh within 2 days\n## ⚠️ Important\n- Yellow rust spreads fast in cool humid weather — spray propiconazole 1 ml/litre\n- Avoid waterlogging — causes root rot and yield loss >50%\n- Do not delay harvest — shattering losses increase after full maturity\n## 💡 Tip\nZero-till sowing after rice saves fuel, retains moisture, and gives 10–15% higher yield.", 'rice': "## Rice Farming Guide (ICAR Recommended)\n## Summary\nRice (Oryza sativa) is India's most important food crop — Kharif season, requires high water.\n## Details\n- **Best varieties:** Swarna, MTU-7029, Pusa Basmati-1121, IR-64, BPT-5204\n- **Soil:** Clay/clay-loam, water-retentive, pH 5.5–7.0\n- **Seed rate:** 20–25 kg/ha (transplanting), 80–100 kg/ha (direct seeding)\n- **Water need:** 1200–1600 mm total\n## Steps\n1. Prepare nursery (25–30 days); treat seeds with Carbendazim 2 g/kg\n2. Puddle field thoroughly; transplant 2–3 seedlings/hill at 20×15 cm\n3. Maintain 2–5 cm water for first 3 weeks\n4. Apply 120 kg N + 60 kg P + 60 kg K/ha in 3 splits\n5. Drain field 10 days before harvest for uniform ripening\n6. Harvest at 20–22% grain moisture; dry to 14% for storage\n## ⚠️ Important\n- Brown Plant Hopper (BPH): drain field immediately if seen; spray buprofezin 1 ml/litre\n- Blast disease: spray tricyclazole 0.6 g/litre at boot leaf stage\n- Avoid excess nitrogen — promotes BPH and neck blast\n## 💡 Tip\nSRI method (single seedling, wider spacing, intermittent irrigation) saves 30% water and increases yield 20–30%.", 'cotton': "## Cotton Farming Guide (ICAR Recommended)\n## Summary\nCotton (Gossypium hirsutum) is India's most important fiber crop — grown in black soil belt.\n## Details\n- **Best varieties:** Bt hybrids (Bollgard-II), NHH-44, RCH-2, MRC-7017\n- **Soil:** Deep black cotton soil (Vertisol), pH 6.0–8.0\n- **Spacing:** 90×60 cm (hybrid), 60×30 cm (desi)\n- **Season:** May–June sowing; picking October–January\n## Steps\n1. Deep summer ploughing (30 cm) to kill soil pests and improve water holding\n2. Sow after first monsoon rain (June); treat seeds with Imidacloprid 5 ml/kg\n3. Basal: 25 kg N + 25 kg P + 25 kg K/ha\n4. Top dress 25 kg N at squaring (45 days) and 25 kg N at flowering (75 days)\n5. Install pheromone traps (5/acre) from 45 days for bollworm monitoring\n6. Pick cotton in early morning; 3–4 pickings at 15-day intervals\n## ⚠️ Important\n- Pink bollworm resistance to Bt is increasing — use refuge crops (non-Bt cotton 20%)\n- Excess nitrogen causes vegetative growth and reduces boll setting\n- Spray only when pest crosses Economic Threshold Level (ETL)\n## 💡 Tip\nIntercrop with cowpea or green gram to improve soil nitrogen and trap pests.", 'maize': '## Maize Farming Guide\n## Summary\nMaize (Zea mays) is a versatile Kharif crop with high yield potential — 6–10 tonnes/ha.\n## Details\n- **Best varieties:** DHM-117, HQPM-1 (QPM), NK-6240, Pioneer-3396\n- **Soil:** Well-drained loamy soil, pH 6.0–7.5\n- **Seed rate:** 20–25 kg/ha; spacing 60×20 cm\n- **Season:** June–July sowing; harvest September–October\n## Steps\n1. Plough 2–3 times; apply FYM 10 tonnes/ha before last plough\n2. Treat seeds with Thiram + Carbendazim (2+1 g/kg)\n3. Sow 3–5 cm deep; thin to one plant per hill at 15 days\n4. Apply 120 kg N + 60 kg P + 40 kg K/ha in splits\n5. Critical irrigations: knee-high stage, tasseling, and grain filling\n6. Harvest when husk turns brown and grain moisture is 25–30%\n## ⚠️ Important\n- Fall Armyworm (FAW) is new invasive pest — spray emamectin benzoate 0.4 g/litre\n- Waterlogging for >48 hours causes complete crop failure\n## 💡 Tip\nBaby corn harvest at 2–3 days after silk emergence gives 3× higher income than grain maize.', 'soybean': '## Soybean Farming Guide\n## Summary\nSoybean is the most important oilseed-cum-pulse crop of central India (MP, Maharashtra).\n## Details\n- **Best varieties:** JS-335, JS-9305, NRC-37, MACS-450\n- **Soil:** Well-drained black/red soil, pH 6.0–7.5\n- **Seed rate:** 70–80 kg/ha; spacing 45×5 cm\n- **Season:** June 20 – July 15 sowing; harvest October\n## Steps\n1. Treat seeds with Rhizobium + PSB culture (5 g/kg each) for nitrogen fixation\n2. Apply 20 kg N + 60 kg P + 40 kg K/ha as basal dose only\n3. Sow 3–4 cm deep after good monsoon rain\n4. One hand weeding at 20–25 days; use pendimethalin 1 litre/ha pre-emergence\n5. Harvest when 95% pods turn brown; thresh immediately to avoid shattering\n## ⚠️ Important\n- Girdle beetle is major pest — remove and destroy affected stems\n- Yellow mosaic virus spreads through whitefly — spray thiamethoxam 0.3 g/litre\n## 💡 Tip\nSoybean fixes 40–60 kg N/ha — next crop needs 25% less nitrogen fertilizer.', 'sugarcane': '## Sugarcane Farming Guide\n## Summary\nSugarcane is a long-duration cash crop (12–18 months) with high water and nutrient needs.\n## Details\n- **Best varieties:** Co-86032, CoJ-64, CoM-0265, CoS-8436\n- **Soil:** Deep loamy soil, pH 6.5–7.5, good drainage\n- **Planting:** February–March (spring) or October–November (autumn)\n- **Spacing:** 90 cm row-to-row; 30–45 cm sett-to-sett\n## Steps\n1. Deep plough 30–45 cm; apply FYM 25 tonnes/ha\n2. Plant 3-budded setts treated with Carbendazim 0.1% solution\n3. Apply 250 kg N + 85 kg P + 85 kg K/ha in 4 splits over the season\n4. Earthing up at 60 and 120 days to prevent lodging\n5. Trash mulching reduces weeds and conserves moisture\n6. Harvest at 12 months for best sugar recovery\n## ⚠️ Important\n- Pyrilla and top borer are major pests — use biocontrol (Trichogramma cards)\n- Ratoon crop needs 20% more nitrogen than plant crop\n## 💡 Tip\nDrip irrigation in sugarcane saves 40% water and increases yield by 20–25%.', 'groundnut': '## Groundnut Farming Guide\n## Summary\nGroundnut (peanut) is the most important oilseed crop of Gujarat, AP, and Tamil Nadu.\n## Details\n- **Best varieties:** GG-20, TAG-24, TG-37A, ICGS-76, Kadiri-6\n- **Soil:** Sandy loam, well-drained, pH 6.0–7.0; calcium-rich soils preferred\n- **Seed rate:** 100–120 kg/ha (bold), 80–100 kg/ha (small)\n- **Season:** Kharif (June–July), Rabi (November–December with irrigation)\n## Steps\n1. Shell pods just before sowing; treat with Thiram 3 g/kg + Rhizobium culture\n2. Sow 5 cm deep at 30×10 cm spacing\n3. Apply 20 kg N + 40 kg P + 40 kg K/ha + gypsum 250 kg/ha at pegging\n4. Earthing up at 30 and 45 days to facilitate pod development\n5. Harvest when inner shell shows dark veins and leaves turn yellow\n## ⚠️ Important\n- Tikka leaf spot: spray mancozeb 2.5 g/litre at 30, 45, 60 days\n- Aflatoxin contamination in stored groundnut — dry to <9% moisture before storage\n## 💡 Tip\nGypsum application at pegging stage is critical — provides calcium directly to developing pods.', 'mustard': '## Mustard Farming Guide\n## Summary\nMustard is the most important Rabi oilseed crop of north India (Rajasthan, UP, Haryana).\n## Details\n- **Best varieties:** Pusa Bold, RH-30, Varuna, Kranti, NRCHB-506\n- **Soil:** Sandy loam to loam, pH 6.0–7.5\n- **Seed rate:** 4–5 kg/ha; spacing 30×10 cm\n- **Season:** October 1–20 sowing; harvest February–March\n## Steps\n1. Fine seedbed preparation; apply FYM 5 tonnes/ha\n2. Treat seeds with Thiram 2.5 g/kg\n3. Apply 80 kg N + 40 kg P + 40 kg K/ha; split N into 2 doses\n4. One irrigation at branching stage is critical if no rain\n5. Harvest when 75% pods turn yellow-brown; thresh immediately\n## ⚠️ Important\n- Aphid is major pest — spray dimethoate 2 ml/litre when 10+ aphids/plant\n- Do not spray during flowering — kills honeybees needed for pollination\n## 💡 Tip\nMustard is an excellent bee-forage crop — keeping beehives increases yield 15–20% through better pollination.', 'potato': "## Potato Farming Guide\n## Summary\nPotato is India's most important vegetable crop — grown in Rabi season with irrigation.\n## Details\n- **Best varieties:** Kufri Jyoti, Kufri Pukhraj, Kufri Sindhuri, Kufri Bahar\n- **Soil:** Sandy loam, well-drained, pH 5.5–6.5\n- **Seed rate:** 2–2.5 tonnes/ha (40–50 g seed tubers)\n- **Season:** October–November planting; January–February harvest\n## Steps\n1. Cut seed tubers to 40–50 g pieces with 2–3 eyes; treat with Mancozeb 3 g/litre\n2. Plant 5–7 cm deep at 60×20 cm spacing\n3. Apply 180 kg N + 80 kg P + 100 kg K/ha; split N into 3 doses\n4. Earthing up at 30 and 45 days — critical for tuber development\n5. Stop irrigation 10 days before harvest; harvest when skin is firm\n## ⚠️ Important\n- Late blight (Phytophthora) spreads rapidly in cool humid weather — spray metalaxyl+mancozeb\n- Store at 2–4°C with 90–95% humidity to prevent sprouting\n## 💡 Tip\nCertified seed from CPRI (Central Potato Research Institute) gives 30–40% higher yield than farm-saved seed.", 'irrigation': '## Irrigation Management Guide\n## Summary\nProper irrigation timing and method can save 30–50% water while maintaining yield.\n## Details\n- **Drip irrigation:** Best for vegetables, fruits, sugarcane — saves 40–50% water\n- **Sprinkler:** Best for wheat, groundnut, vegetables — saves 25–35% water\n- **Flood irrigation:** Traditional method — least efficient, use only where water is abundant\n- **Critical stages:** Flowering and grain filling need water most\n## Steps\n1. Check soil moisture by feel — if soil ball breaks easily, irrigation is needed\n2. Irrigate in early morning or evening to reduce evaporation\n3. Apply water slowly to prevent runoff and erosion\n4. Use tensiometer or soil moisture sensor for precision irrigation\n5. Maintain irrigation channels to prevent seepage losses\n## ⚠️ Important\n- Over-irrigation causes waterlogging, root rot, and nutrient leaching\n- Saline water (EC >4 dS/m) damages most crops — test water quality\n## 💡 Tip\nPM Krishi Sinchai Yojana provides 55% subsidy on drip/sprinkler systems — apply at district agriculture office.', 'organic': '## Organic Farming Guide\n## Summary\nOrganic farming avoids synthetic chemicals and builds long-term soil health.\n## Details\n- **Key inputs:** FYM, vermicompost, green manure, biofertilizers, neem-based pesticides\n- **Certification:** NPOP (National Programme for Organic Production) — takes 3 years conversion\n- **Premium price:** Organic produce gets 20–50% higher price in market\n- **Suitable crops:** Vegetables, spices, basmati rice, fruits\n## Steps\n1. Stop all synthetic fertilizers and pesticides — start conversion period\n2. Apply FYM 10–15 tonnes/ha + vermicompost 2–3 tonnes/ha annually\n3. Use Rhizobium, PSB, KSB biofertilizers for nutrient supply\n4. Manage pests with neem oil, Bt spray, pheromone traps, sticky traps\n5. Apply for Participatory Guarantee System (PGS) certification — cheaper than NPOP\n## ⚠️ Important\n- Yield may drop 20–30% in first 2–3 years during conversion\n- Organic certification is mandatory to sell at premium price\n## 💡 Tip\nParamparagat Krishi Vikas Yojana (PKVY) provides Rs.50,000/ha over 3 years for organic farming clusters.', 'pest_general': '## General Pest Management (IPM)\n## Summary\nIntegrated Pest Management (IPM) reduces pesticide use by 50% while protecting yield.\n## Details\n- **IPM principle:** Use chemical pesticides only as last resort\n- **Monitoring:** Scout fields twice a week; act only at Economic Threshold Level (ETL)\n- **Biological control:** Trichogramma cards, NPV, Bt spray, predatory insects\n- **Cultural control:** Crop rotation, resistant varieties, timely sowing, field sanitation\n## Steps\n1. Monitor crop weekly — count pests per plant/leaf\n2. Use yellow/blue sticky traps to monitor flying insects\n3. Install pheromone traps for bollworm, fruit borer monitoring\n4. Apply neem oil 5 ml/litre as first line of defense\n5. Use chemical pesticides only when pest crosses ETL\n6. Rotate pesticide groups to prevent resistance\n## ⚠️ Important\n- Never mix pesticides without checking compatibility\n- Observe pre-harvest interval (PHI) — do not harvest before PHI days after spraying\n- Wear full protective gear: gloves, mask, goggles, full-body cover\n## 💡 Tip\nNSKE (Neem Seed Kernel Extract) 5% is as effective as many chemical pesticides and costs 80% less.', 'market_general': '## Market & Price Information (Offline Reference)\n## Summary\nApproximate MSP and market price ranges for major crops in India (2024-25).\n## Details\n- **Wheat MSP:** Rs.2,275/quintal (2024-25)\n- **Rice (Common) MSP:** Rs.2,300/quintal\n- **Maize MSP:** Rs.2,090/quintal\n- **Soybean MSP:** Rs.4,892/quintal\n- **Cotton (Medium) MSP:** Rs.7,121/quintal\n- **Groundnut MSP:** Rs.6,783/quintal\n- **Mustard MSP:** Rs.5,950/quintal\n- **Onion:** Market price Rs.800–2,500/quintal (highly variable)\n- **Tomato:** Market price Rs.500–4,000/quintal (seasonal)\n## Steps\n1. Check eNAM portal (enam.gov.in) for live mandi prices\n2. Register on eNAM to sell directly to buyers across India\n3. Check Agmarknet (agmarknet.gov.in) for historical price trends\n4. Sell when price is 10–15% above MSP for best returns\n## ⚠️ Important\n- MSP is minimum support price — government buys at this price through NAFED/FCI\n- Onion and tomato prices are highly volatile — consider cold storage\n## 💡 Tip\nFarmer Producer Organizations (FPOs) get better prices through collective bargaining — join or form one.', 'schemes_general': "## Government Schemes for Farmers (Offline Reference)\n## Summary\nKey central government schemes providing financial support to Indian farmers.\n## Details\n- **PM-KISAN:** Rs.6,000/year direct transfer to all farmers — register at pmkisan.gov.in\n- **PMFBY:** Crop insurance at 1.5–2% premium for Rabi, 2% for Kharif — apply at bank\n- **KCC (Kisan Credit Card):** Crop loan at 4% interest up to Rs.3 lakh — apply at any bank\n- **PM Krishi Sinchai Yojana:** 55% subsidy on drip/sprinkler — apply at district office\n- **PKVY:** Rs.50,000/ha for organic farming clusters over 3 years\n- **Soil Health Card:** Free soil testing every 2 years — contact local agriculture officer\n- **eNAM:** Online mandi platform for better price discovery — register free\n## Steps\n1. PM-KISAN: Register at pmkisan.gov.in with Aadhaar + bank account + land records\n2. PMFBY: Apply at bank or CSC before crop sowing cutoff date\n3. KCC: Visit nearest bank with land records, Aadhaar, and passport photo\n## ⚠️ Important\n- PMFBY enrollment deadline is before sowing — do not miss it\n- PM-KISAN requires land records in farmer's name — update records if needed\n## 💡 Tip\nAll schemes can be applied through Common Service Centres (CSC/Jan Seva Kendra) in your village.", 'weather_general': '## Weather & Farming Calendar (Offline Reference)\n## Summary\nSeason-wise farming calendar and weather patterns for Indian agriculture.\n## Details\n- **Kharif season (Jun–Oct):** Sow after first monsoon rain — rice, cotton, maize, soybean, groundnut\n- **Rabi season (Nov–Mar):** Sow after monsoon withdrawal — wheat, mustard, potato, chickpea\n- **Zaid season (Mar–Jun):** Short-duration crops with irrigation — watermelon, cucumber, moong\n- **Monsoon onset:** Kerala June 1, Maharashtra June 10–15, North India June 25–July 5\n- **Monsoon withdrawal:** North India September 15–October 1\n## Steps\n1. Kharif: Prepare field in May; sow within 1 week of first good rain\n2. Rabi: Sow wheat/mustard by November 15 for best yield\n3. Monitor IMD (imd.gov.in) for weekly weather forecasts\n4. Protect crops during hailstorm/frost with smoke screens or covers\n## ⚠️ Important\n- Late monsoon onset: use short-duration varieties to complete crop before frost\n- Frost risk for potato/tomato below 4°C — irrigate before frost night\n- Hailstorm damage: apply urea spray 1% + fungicide after hail to help recovery\n## 💡 Tip\nAgromet Advisory Services (AAS) from IMD provides 5-day crop-specific weather advisories — subscribe free via SMS.', 'soil_health': '## Soil Health Management Guide\n## Summary\nHealthy soil is the foundation of good yield — focus on organic matter and pH balance.\n## Details\n- **Ideal soil pH:** 6.0–7.5 for most crops; below 5.5 causes nutrient lockup\n- **Organic matter:** Should be >0.75%; most Indian soils are deficient\n- **Micronutrients:** Zinc deficiency in 50% Indian soils; boron deficiency in eastern India\n- **Soil structure:** Good tilth allows root penetration and water infiltration\n## Steps\n1. Test soil every 2–3 years at KVK or soil testing lab\n2. Apply lime (CaCO3) 2–4 tonnes/ha if pH below 5.5\n3. Apply FYM/compost 5–10 tonnes/ha annually to build organic matter\n4. Apply zinc sulphate 25 kg/ha if zinc deficiency (white bud in maize, khaira in rice)\n5. Deep ploughing once in 3 years to break hardpan\n## ⚠️ Important\n- Burning crop residue destroys soil organic matter and beneficial microbes\n- Continuous use of same fertilizer without soil test causes nutrient imbalance\n## 💡 Tip\nGreen manuring with dhaincha or sunhemp adds 60–80 kg N/ha and improves soil structure at very low cost.'}

OFFLINE_KEYWORDS = {'wheat': ['wheat', 'gehun', 'gehu', 'गेहूं', 'गेहु'], 'rice': ['rice', 'paddy', 'dhan', 'chawal', 'dhaan', 'धान', 'चावल'], 'cotton': ['cotton', 'kapas', 'कपास', 'kapas'], 'maize': ['maize', 'corn', 'makka', 'makkai', 'मक्का'], 'soybean': ['soybean', 'soya', 'soyabean', 'soyabin', 'सोयाबीन'], 'sugarcane': ['sugarcane', 'ganna', 'गन्ना', 'ikh'], 'groundnut': ['groundnut', 'peanut', 'moongphali', 'मूंगफली'], 'mustard': ['mustard', 'sarson', 'सरसों', 'rapeseed'], 'potato': ['potato', 'aloo', 'आलू', 'batata'], 'tomato': ['tomato', 'tamatar', 'टमाटर'], 'onion': ['onion', 'pyaz', 'kanda', 'प्याज'], 'irrigation': ['irrigation', 'sinchai', 'सिंचाई', 'drip', 'sprinkler', 'water management'], 'organic': ['organic', 'jaivik', 'जैविक', 'natural farming', 'prakriti'], 'pest_general': ['pest', 'insect', 'kida', 'कीड़ा', 'ipm', 'spray', 'pesticide'], 'aphid': ['aphid', 'maahu', 'माहू', 'louse', 'chepaa'], 'bollworm': ['bollworm', 'boll worm', 'इल्ली', 'heliothis'], 'soil test': ['soil test', 'mitti jaanch', 'मिट्टी जांच', 'npk', 'soil health card'], 'soil_health': ['soil health', 'organic matter', 'soil ph', 'zinc', 'micronutrient', 'mitti'], 'fertilizer': ['fertilizer', 'urea', 'dap', 'khad', 'खाद', 'उर्वरक', 'npk', 'nutrient'], 'drought': ['drought', 'sukha', 'सूखा', 'water stress', 'no rain', 'dry spell'], 'flood': ['flood', 'waterlog', 'बाढ़', 'जलभराव', 'excess water', 'heavy rain damage'], 'market_general': ['market', 'price', 'msp', 'mandi', 'rate', 'sell', 'bhav', 'भाव', 'दाम'], 'schemes_general': ['scheme', 'yojana', 'subsidy', 'loan', 'kcc', 'pmkisan', 'insurance', 'pmfby', 'सब्सिडी'], 'weather_general': ['weather', 'season', 'monsoon', 'kharif', 'rabi', 'forecast', 'मौसम', 'बारिश']}


def find_offline_answer(query: str):
    q = query.lower()
    for topic, keywords in OFFLINE_KEYWORDS.items():
        if any(kw in q for kw in keywords):
            return OFFLINE_KB.get(topic)
    return None

def offline_chat(message: str) -> dict:
    answer = find_offline_answer(message)
    if answer:
        return {'reply': answer + chr(10)+chr(10)+'---'+chr(10)+'*Offline mode - ICAR-based local knowledge base*', 'suggestions': [], 'blocked': False, 'offline': True}
    return {'reply': 'Not available offline. Topics: wheat, rice, cotton, maize, soybean, sugarcane, groundnut, mustard, potato, tomato, onion, irrigation, organic, pest, soil, fertilizer, drought, flood, market prices, schemes, weather.', 'suggestions': [], 'blocked': False, 'offline': True}

def offline_market(crop: str, location: str) -> dict:
    MSP = {'wheat':2275,'rice':2300,'maize':2090,'soybean':4892,'cotton':7121,'groundnut':6783,'mustard':5950,'sugarcane':340,'onion':1200,'tomato':1500,'potato':800,'chickpea':5440,'moong':8682,'urad':7400,'arhar':7550}
    price = MSP.get(crop.lower().strip(), 2000)
    return {'current_price_per_kg': round(price/100,2), 'predicted_price_7d': round(price/100*1.02,2), 'predicted_price_30d': round(price/100*1.05,2), 'best_sell_window': 'Check eNAM when online', 'trend': 'stable', 'price_factors': f'Offline MSP for {crop}: Rs.{price}/quintal. Check Agmarknet for live prices.', 'offline': True}

def offline_weather(location: str) -> dict:
    return {'location': location+' (offline)', 'temp': 28, 'feels_like': 30, 'description': 'Typical seasonal conditions', 'icon': 'partly_sunny', 'humidity': 65, 'wind': 12, 'pressure': 1013, 'uv_index': 6, 'rain_now': 0, 'alerts': ['Offline mode - showing typical seasonal data'], 'forecast': [{'day': d, 'date': '', 'icon': 'sun', 'desc': 'Typical', 'max': 32, 'min': 20, 'rain_mm': 2, 'rain_prob': 20, 'wind_max': 15, 'uv': 6, 'sunrise': '06:15', 'sunset': '18:45'} for d in ['Mon','Tue','Wed','Thu','Fri','Sat','Sun','Mon','Tue','Wed']], 'offline': True}

_dir = os.path.dirname(os.path.abspath(__file__))
_schemes_path = os.path.join(_dir, '../../data/schemes.json')

def offline_schemes(query: str, state: str = '', crop: str = '', category: str = 'small') -> dict:
    try:
        with open(_schemes_path, encoding='utf-8') as f:
            schemes = json.load(f)
        q = query.lower()
        scored = [(sum(1 for w in q.split() if len(w)>2 and w in json.dumps(s).lower()) + (2 if state and state.lower() in json.dumps(s).lower() else 0) + (2 if crop and crop.lower() in json.dumps(s).lower() else 0), s) for s in schemes]
        scored.sort(key=lambda x: -x[0])
        matched = [s for _, s in scored[:3]] or schemes[:3]
        return {'schemes': matched, 'summary': 'Offline mode - best matching schemes from local database.', 'offline': True}
    except Exception:
        return {'schemes': [], 'summary': 'Scheme data not available offline.', 'offline': True}
